INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00169', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲貸與乙新臺幣100萬元後，因自己需款孔急，乃於清償期屆至前，未得乙之同意，將對乙之前述 債權讓與於丙，但未通知乙該情事。下列敘述，何者正確？', '["因事前未得乙之同意，該債權讓與無效", "因事前未得乙之同意，乙得撤銷該債權讓與", "因甲、丙均未通知乙，該債權讓與無效", "該債權讓與在甲丙間有效，但因甲或丙未通知乙，對乙不生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00170', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '農育權乃用益物權之一。下列關於農育權之敘述，何者錯誤？', '["農育權人不得因使用便利而為特別改良", "得於農作、森林、養殖、畜牧、種植竹木或保育之目的範圍內，設定農育權", "農育權未定有期限時，除以造林、保育為目的者外，當事人得隨時終止之", "農育權人除另有習慣外，原則上不得將土地出租於他人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00171', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '權利質權，乃以可讓與之債權或其他權利為標的之質權。下列關於權利質權之敘述，何者錯誤？', '["以不動產物權之設定或移轉為給付內容之債權，得為權利質權之標的物", "以債權為標的物之質權，其設定應以書面為之", "為質權標的物之權利，非經質權人之同意，出質人不得以法律行為，使其消滅或變更", "質權以債權為標的物者，其債務人不得為清償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00172', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲將垃圾棄置於乙之土地上，下列敘述，何者正確？', '["乙對甲得主張所有物返還請求權", "乙對甲得請求除去所有權之妨害", "乙對甲得請求防止所有權之妨害", "乙對甲得主張占有物返還請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00173', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲乙丙三人分別共有A地，應有部分各三分之一。下列關於共有物分割之敘述，依民法規定，何 者正確？', '["共有物分割請求權之性質，為支配權", "共有物分割行為之性質，屬處分行為", "共有物分割之協議性質，為物權契約", "共有物分割判決之性質，為給付判決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00174', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲在其所有之A地興建B屋，並將B屋出租於乙，租期10年，並經公證在案。嗣後甲為擔保丙之新 臺幣1000萬元債權，將A地設定普通抵押權於丙。甲屆期無法清償債務。下列敘述，何者正確？', '["抵押權人丙得聲請法院拍賣A地，就其賣得價金受清償", "丙於必要時，得於強制執行程序中，聲請法院將A地及B屋併付拍賣", "法院應將A地及B屋併付拍賣，以避免土地與房屋各異其所有人之情形", "若由丁拍得A地，於房屋租賃存續期間內，丁仍得依所有物返還請求權請求乙返還B屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00175', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲於自有A地上興建B屋，完工後數年，將A地、B屋先後分別出賣於乙、丙，並分別完成所有權 移轉登記。丙將B屋出租於丁，丁入住後數月竟遭戊強占房屋。下列敘述，何者正確？', '["甲於出售B屋時，A地所有人乙有依同樣條件優先購買之權", "丙得請求乙向地政機關申請普通地上權登記", "乙得請求丙拆屋還地", "丁得依占有人物上請求權規定，請求戊返還B屋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00176', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何種情形，仍須雙方當事人一同至戶政機關辦理離婚登記，始生離婚之效力？', '["離婚經當事人自行協議", "離婚經法院調解成立", "離婚經法院判決", "離婚在法院和解成立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00177', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲、乙結婚後，某日甲向市場攤商丙買魚，忘記帶錢，暫時賒帳。嗣後乙至市場時，丙向乙請求 給付甲所積欠之價金，有無理由？', '["無理由，因買賣契約存在於甲丙間，乙並非當事人", "無理由，因甲在代理乙為日常家務時，並未向丙表明甲是代理人、乙是本人", "有理由，因魚之價金屬於家庭生活費用所生之債務，甲乙應連帶負責", "有理由，因甲乙婚後所負之債務均為雙方共有，乙應對婚後債務負責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00178', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲年幼時父母雙亡，由同居之祖母乙任監護人。甲現年17歲，下列何種行為無須得乙之同意？', '["甲撰寫自書遺囑，將存款新臺幣10萬元遺贈於女友丙", "甲與丁訂立土地買賣契約", "甲向戊銀行貸款，並將自己之土地設定普通抵押權於戊", "甲欲與己庚夫妻訂立收養契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
